    public void TopConsumers_NegativeN_ReturnsEmpty()
    {
        var processes = new List<ProcessInfo>
        {
            new(Pid: 1, Name: "proc", CpuPercent: 50.0, MemoryMb: 1000.0),
        };

        var result = TopConsumers.ByCpu(processes, -1);

        Assert.Empty(result);
    }

